import re, pathlib
p = pathlib.Path('/Users/gbang/Downloads/algora/workspace/4a62b31b-dc67-4dfc-a120-8a9e6d99bfb5_hld/_response.md')
md = p.read_text()
blocks = re.findall(r'```mermaid\n(.*?)```', md, re.S)

bad = set('():;/<>{}')   # the chars that break INSIDE label text
problems = 0
for i,b in enumerate(blocks):
    # edge label text between |"..."| or |...|
    for m in re.findall(r'\|"?([^|"]+)"?\|', b):
        h = [c for c in m if c in bad]
        if h: problems+=1; print(f"EDGE block{i}: {m!r} {h}")
    # node display text: capture the innermost text of [text], [[text]], [(text)]
    for m in re.findall(r'\[+\(?([^\[\]\(\)]+)\)?\]+', b):
        h = [c for c in m if c in bad]
        if h: problems+=1; print(f"NODE block{i}: {m!r} {h}")
    # subgraph titles
    for m in re.findall(r'subgraph\s+\w+\["([^"]+)"\]', b):
        h = [c for c in m if c in bad]
        if h: problems+=1; print(f"SUBG block{i}: {m!r} {h}")
print("PROBLEMS (real breaking chars in label TEXT):", problems)
